import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ItemCategory {
  FURNITURE = 'Furniture',
  ART = 'Art',
  TURNIPS = 'Turnips',
  DIY = 'DIY Recipes',
  CLOTHING = 'Clothing'
}

export interface ArtItem {
  id: string;
  name: string;
  isReal: boolean;
  description: string;
  rarity: 'Common' | 'Rare' | 'Ultra-Rare';
  imageUrl: string;
  fakeDetail: string;
}

export interface Listing {
  id: string;
  title: string;
  category: ItemCategory;
  price: string;
  seller: string;
  sellerRating: number;
  timestamp: string;
  imageUrl: string;
  description: string;
}

export interface TurnipPricePoint {
  day: string;
  period: 'AM' | 'PM';
  price: number;
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const verifyArtWithAI = async (itemName: string, userDescription: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `In Animal Crossing: New Horizons, I'm looking at an art piece called "${itemName}". Here's what it looks like: ${userDescription}. Tell me if it is likely to be the REAL version or the FAKE version based on how Redd sells them. Explain the specific detail I should look for.`,
      config: {
        temperature: 0.7,
        maxOutputTokens: 500,
      }
    });

    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "I'm having trouble identifying this right now. Please check our official guide!";
  }
};

export const getTurnipAdvice = async (prices: number[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `My turnip prices this week are: ${prices.join(', ')}. Based on Animal Crossing New Horizons patterns (Small Spike, Large Spike, Fluctuating, Decreasing), what pattern am I likely in and should I sell now or wait? Keep it brief.`,
    });
    return response.text;
  } catch (error) {
    return "The Stalk Market is unpredictable today! Keep an eye on those trends.";
  }
};

