            type="text" 
            placeholder="Search items, sets, villagers..." 
            className="w-full pl-10 pr-4 py-3 bg-white border border-gray-100 rounded-2xl focus:ring-2 focus:ring-[#5EB970] focus:border-transparent outline-none shadow-sm"
