      <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
        {categories.map((cat) => (
          <button 
            key={cat}
            onClick={() => setFilter(cat as any)}
            className={`px-5 py-2 rounded-full font-semibold whitespace-nowrap transition-all ${
              filter === cat 
                ? 'bg-[#5EB970] text-white shadow-md' 
                : 'bg-white text-gray-500 border border-gray-100 hover:border-green-200'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredListings.map((listing) => (
          <div key={listing.id} className="acnh-card flex flex-col overflow-hidden hover:shadow-xl transition-all cursor-pointer group">
            <div className="relative h-48 bg-gray-100">
              <img src={listing.imageUrl} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" alt={listing.title} />
              <div className="absolute top-3 left-3 px-3 py-1 bg-white/90 backdrop-blur-sm rounded-full text-xs font-bold text-[#5EB970] shadow-sm">
                {listing.category}
              </div>
            </div>
            <div className="p-5 flex flex-col flex-1">
