export default Marketplace;

import React, { useState } from 'react';
import { Palette, Search, ShieldCheck, HelpCircle, Loader2 } from 'lucide-react';
import { verifyArtWithAI } from '../services/geminiService';

const ArtVerification: React.FC = () => {
  const [artName, setArtName] = useState('');
  const [description, setDescription] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [result, setResult] = useState<string | null>(null);

  const handleVerify = async () => {
    if (!artName || !description) return;
    setIsLoading(true);
    const feedback = await verifyArtWithAI(artName, description);
    setResult(feedback);
    setIsLoading(false);
  };

  return (
    <div className="max-w-3xl mx-auto space-y-8">
      <div className="text-center space-y-2">
        <h2 className="text-3xl font-bold text-gray-800">Blathers' Appraisal Assistant</h2>
        <p className="text-gray-500">Don't get fooled by Redd's cousins! Use our AI expert to verify authenticity.</p>
      </div>

      <div className="acnh-card p-6 md:p-8 space-y-6">
        <div className="flex items-center gap-3 p-4 bg-blue-50 text-blue-700 rounded-2xl border border-blue-100">
          <HelpCircle size={20} />
          <p className="text-sm">Describe the detail of the art piece (e.g., "The Mona Lisa has eyebrows" or "The statue is holding a book").</p>
        </div>

        <div className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">Artwork Name</label>
            <input 
              type="text" 
              placeholder="e.g. Jolly Painting, Valiant Statue..." 
              className="w-full px-4 py-3 bg-white border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#5EB970] shadow-sm"
              value={artName}
              onChange={(e) => setArtName(e.target.value)}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2">What do you see?</label>
            <textarea 
              rows={4}
              placeholder="Describe the colors, characters, or specific oddities..." 
              className="w-full px-4 py-3 bg-white border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-[#5EB970] shadow-sm"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>
          <button 
            onClick={handleVerify}
            disabled={isLoading || !artName || !description}
            className="w-full bg-[#5EB970] text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:shadow-lg disabled:opacity-50 transition-all active:scale-[0.98]"
          >
            {isLoading ? <Loader2 className="animate-spin" /> : <ShieldCheck size={20} />}
            Appraise Artwork
          </button>
        </div>

        {result && (
          <div className="mt-8 p-6 bg-green-50 rounded-2xl border-2 border-dashed border-[#5EB970] animate-in slide-in-from-bottom-4 duration-500">
            <div className="flex items-center gap-2 mb-4 text-[#5EB970]">
              <ShieldCheck size={24} />
              <h4 className="font-bold text-lg">Appraisal Result</h4>
            </div>
            <div className="prose prose-green max-w-none text-gray-700 leading-relaxed">
              {result.split('\n').map((para, i) => <p key={i} className="mb-2">{para}</p>)}
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="acnh-card p-4 flex items-center gap-4 opacity-80">
          <img src="https://picsum.photos/seed/statue1/100/100" className="w-16 h-16 rounded-xl object-cover" alt="Guide" />
          <div>
            <p className="font-bold text-gray-800">Statue Guide</p>
            <p className="text-xs text-gray-400">View visual differences</p>
          </div>
        </div>
        <div className="acnh-card p-4 flex items-center gap-4 opacity-80">
          <img src="https://picsum.photos/seed/painting1/100/100" className="w-16 h-16 rounded-xl object-cover" alt="Guide" />
          <div>
            <p className="font-bold text-gray-800">Painting Guide</p>
            <p className="text-xs text-gray-400">Common fake details</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ArtVerification;

