              padding={{ left: 10, right: 10 }}
            />
            <YAxis stroke="#94a3b8" fontSize={10} tickLine={false} axisLine={false} />
            <Tooltip 
              contentStyle={{ borderRadius: '1.25rem', border: 'none', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
              labelStyle={{ color: '#94a3b8', fontSize: '10px', marginBottom: '4px', fontWeight: 'bold' }}
              itemStyle={{ color: '#B1D34A', fontWeight: 'bold', fontSize: '14px' }}
