          </h3>
          <div className="text-[10px] font-bold text-gray-400 bg-gray-50 px-3 py-1 rounded-full uppercase tracking-wider">
            目前：120 鈴錢
          </div>
        </div>
        <ResponsiveContainer width="100%" height="80%">
          <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
            <defs>
              <linearGradient id="colorPrice" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#B1D34A" stopOpacity={0.2}/>
                <stop offset="95%" stopColor="#B1D34A" stopOpacity={0}/>
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="#f0fdf4" vertical={false} />
            <XAxis 
              dataKey="name" 
              stroke="#94a3b8" 
              fontSize={11} 
              tickLine={false} 
              axisLine={false} 
              interval={1} 
              tick={{ fontWeight: 600 }}
              padding={{ left: 10, right: 10 }}
            />
            <YAxis stroke="#94a3b8" fontSize={10} tickLine={false} axisLine={false} />
            <Tooltip 
              contentStyle={{ borderRadius: '1.25rem', border: 'none', boxShadow: '0 10px 25px -5px rgba(0,0,0,0.1)', padding: '12px' }}
              labelStyle={{ color: '#94a3b8', fontSize: '10px', marginBottom: '4px', fontWeight: 'bold' }}
              itemStyle={{ color: '#B1D34A', fontWeight: 'bold', fontSize: '14px' }}
              labelFormatter={(value, payload) => payload[0]?.payload?.fullLabel || value}
              formatter={(value) => [`${value} 鈴錢`, '價格']}
            />
            {/* type="monotone" provides a smooth cubic spline which is gentle yet reflects fluctuations well */}
            <Area 
              type="monotone" 
              dataKey="price" 
              stroke="#B1D34A" 
              strokeWidth={4} 
              fillOpacity={1} 
              fill="url(#colorPrice)" 
              animationDuration={1500}
            />
