          <button className="text-xs font-bold text-[#B1D34A] hover:underline">查看全部</button>
        </div>
        <div className="divide-y divide-gray-50">
          {[582, 450, 390].map((price, i) => (
            <div key={i} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
              <div className="flex items-center gap-3">
                <div className="w-10 h-10 rounded-xl bg-[#E0F2F1] flex items-center justify-center text-[#00897B] font-bold text-sm">
                  {['M', 'C', 'P'][i]}
