                </div>
              </div>
              <div className="text-right">
                <p className="text-lg font-bold text-[#B1D34A]">{price} 鈴錢</p>
                <button className="text-[10px] bg-green-50 text-[#B1D34A] px-3 py-1 rounded-full font-bold mt-1">加入排隊</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

