      if (activeFilter === '500+') return priceValue >= 500;
      if (activeFilter === '400+') return priceValue >= 400;
      if (activeFilter === '300+') return priceValue >= 300;
      if (activeFilter === '北半球') return item.hemisphere === 'North';
