      {/* Update Price Modal - Now as a page-level popup */}
      {isModalOpen && (
        <UpdatePriceModal 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={handleUpdateSubmit}
        />
      )}
    </div>
  );
};

export default TurnipExchange;

