import React, { useState, useEffect } from 'react';
import { 
  ShoppingBag, 
  TrendingUp, 
  BookOpen, 
  User, 
  Bell, 
  Plus,
  Leaf,
  CheckCircle2
} from 'lucide-react';
import HomeView from './components/HomeView';
import Marketplace from './components/Marketplace';
import ArtVerification from './components/ArtVerification';
import TurnipExchange from './components/TurnipExchange';
import Profile from './components/Profile';
import LoginView from './components/LoginView';
import CreateListing from './components/CreateListing';
import NotificationsModal from './components/NotificationsModal';
import { UserProfile } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'market' | 'track' | 'guide' | 'profile'>('market');
  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);
  const [isCreatingListing, setIsCreatingListing] = useState(false);
  const [isShowingNotifications, setIsShowingNotifications] = useState(false);
  const [notificationCount, setNotificationCount] = useState(2);
  const [showSuccessToast, setShowSuccessToast] = useState(false);

  useEffect(() => {
    let timer: number;
    if (showSuccessToast) {
      // Auto-hide success toast after 1 second
      timer = window.setTimeout(() => {
        setShowSuccessToast(false);
      }, 1000);
    }
    return () => clearTimeout(timer);
  }, [showSuccessToast]);

  const handleLogin = (profile: UserProfile) => {
    setUserProfile({
      ...profile,
      avatarUrl: 'https://picsum.photos/seed/user-avatar/200/200',
      passportNumber: 'SW-1234-5678-9012'
    });
    setActiveTab('market');
  };

  const handleLogout = () => {
    setUserProfile(null);
    setActiveTab('market');
  };

  const handleCreateSuccess = () => {
    setIsCreatingListing(false);
    setShowSuccessToast(true);
  };

  const openNotifications = () => {
    setIsShowingNotifications(true);
    setNotificationCount(0); // Mark as seen
  };

  const handleClearNotifications = () => {
    setNotificationCount(0);
    setIsShowingNotifications(false);
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'market': return <Marketplace />;
      case 'track': return <TurnipExchange />;
      case 'guide': return <ArtVerification />;
      case 'profile': return userProfile ? <Profile userProfile={userProfile} onUpdateProfile={setUserProfile} onLogout={handleLogout} /> : null;
      default: return <Marketplace />;
    }
  };

  if (!userProfile) {
    return (
      <div className="app-shell">
        <LoginView onLogin={handleLogin} />
      </div>
    );
  }

  return (
    <div className="app-shell relative">
      {/* Success Toast */}
      {showSuccessToast && (
        <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[100] w-full max-w-[280px] animate-in slide-in-from-top-4 fade-in duration-300">
          <div className="bg-[#B1D34A] text-white px-6 py-4 rounded-[2rem] shadow-xl flex items-center justify-center gap-3 border-4 border-white">
            <CheckCircle2 size={24} strokeWidth={3} />
            <span className="font-black text-lg">提交成功！</span>
          </div>
        </div>
      )}

      {/* App Header */}
      <header className="px-6 pt-10 pb-4 flex items-center justify-between bg-[#B1D34A] sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-[#B1D34A] shadow-sm">
            <Leaf size={22} fill="currentColor" />
          </div>
          <h1 className="text-2xl font-bold text-white tracking-tight">NookTrade</h1>
        </div>
        <button 
          onClick={openNotifications}
          className="w-10 h-10 flex items-center justify-center text-white relative transition-transform active:scale-90"
        >
          <Bell size={28} />
          {notificationCount > 0 && (
            <span className="absolute top-0 right-0 w-5 h-5 bg-[#E74C3C] text-white text-[10px] font-bold rounded-full border-2 border-[#B1D34A] flex items-center justify-center animate-in zoom-in duration-300">
              {notificationCount}
            </span>
          )}
        </button>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto hide-scrollbar bg-[#F9F9F2]">
        <div className="px-5 pt-4 pb-28">
          {renderContent()}
        </div>
      </main>

      {/* Floating Action Button */}
      <div className="fixed bottom-12 left-1/2 -translate-x-1/2 z-50">
        <button 
          onClick={() => setIsCreatingListing(true)}
          className="w-16 h-16 bg-[#B1D34A] border-4 border-white text-white rounded-full flex items-center justify-center shadow-lg fab-shadow transition-transform active:scale-90"
        >
          <Plus size={36} strokeWidth={3} />
        </button>
      </div>

      {/* App Bottom Navigation */}
      <nav className="fixed bottom-0 left-1/2 -translate-x-1/2 w-full max-w-[500px] bg-white border-t border-gray-100 px-4 py-2 flex justify-between items-center z-40">
        <TabItem icon={<ShoppingBag />} active={activeTab === 'market'} onClick={() => setActiveTab('market')} label="市場" />
        <TabItem icon={<TrendingUp />} active={activeTab === 'track'} onClick={() => setActiveTab('track')} label="追蹤" />
        <div className="w-16" /> {/* Spacer for FAB */}
        <TabItem icon={<BookOpen />} active={activeTab === 'guide'} onClick={() => setActiveTab('guide')} label="指南" />
        <TabItem icon={<User />} active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} label="個人" />
      </nav>

      {/* Modal Overlay for Create Listing */}
      {isCreatingListing && (
        <CreateListing 
          onClose={() => setIsCreatingListing(false)} 
          onSuccess={handleCreateSuccess}
        />
      )}

      {/* Notifications Modal Overlay */}
      {isShowingNotifications && (
        <NotificationsModal 
          onClose={() => setIsShowingNotifications(false)} 
          onClear={handleClearNotifications}
        />
      )}
    </div>
  );
};

interface TabItemProps {
  // Fix: Using any generic to allow cloneElement to inject size/strokeWidth props without TS error
  icon: React.ReactElement<any>;
  active: boolean;
  onClick: () => void;
  label: string;
}

const TabItem: React.FC<TabItemProps> = ({ icon, active, onClick, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 min-w-[64px] transition-all duration-300 ${
      active ? 'text-[#B1D34A]' : 'text-[#8E8E8E]'
    }`}
  >
    <div className={`p-1.5 px-3 rounded-full transition-all ${active ? 'bg-[#F9FCF0]' : ''}`}>
      {/* Applying size and strokeWidth to cloned lucide icons */}
      {React.cloneElement(icon, { size: 24, strokeWidth: active ? 2.5 : 2 })}
    </div>
    <span className="text-[10px] font-bold">{label}</span>
  </button>
);

export default App;

import React, { useState } from 'react';
import { X, Plane, Trash2, CheckCircle2, Circle } from 'lucide-react';

interface Notification {
  id: string;
  user: string;
  island: string;
  time: string;
  type: 'arrival' | 'departure';
  isRead: boolean;
}

interface NotificationsModalProps {
  onClose: () => void;
  onClear: () => void;
}

const INITIAL_NOTIFICATIONS: Notification[] = [
  { id: 'n1', user: '狸克', island: '發財島', time: '5 分鐘前', type: 'arrival', isRead: false },
  { id: 'n2', user: '西施惠', island: '行政島', time: '12 分鐘前', type: 'departure', isRead: false },
  { id: 'n3', user: '傅達', island: '化石島', time: '1 小時前', type: 'arrival', isRead: true },
  { id: 'n4', user: '莫里', island: '機場島', time: '3 小時前', type: 'departure', isRead: true },
];

const NotificationsModal: React.FC<NotificationsModalProps> = ({ onClose, onClear }) => {
  const [notifications, setNotifications] = useState<Notification[]>(INITIAL_NOTIFICATIONS);

  const markAsRead = (id: string) => {
    setNotifications(prev => 
      prev.map(n => n.id === id ? { ...n, isRead: true } : n)
    );
  };

  const markAllRead = () => {
    setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
  };

  const hasUnread = notifications.some(n => !n.isRead);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-black/40 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="w-full max-w-sm bg-white rounded-[3rem] p-8 shadow-2xl border-4 border-[#B1D34A] scale-in-center animate-in zoom-in-95 duration-300 relative overflow-hidden flex flex-col max-h-[75vh]">

        {/* Close Button */}
        <button 
          onClick={onClose}
          className="absolute top-6 right-6 w-10 h-10 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors z-10"
        >
          <X size={20} />
        </button>

        <div className="space-y-6 flex-1 flex flex-col overflow-hidden">
          {/* Header */}
          <div className="text-center space-y-1 shrink-0">
            <h3 className="text-2xl font-black text-[#5C5C4D]">最近消息</h3>
            <div className="flex items-center justify-center gap-2">
              <p className="text-xs font-bold text-[#8E8E81] opacity-70">查看造訪您島嶼的玩家</p>
              {hasUnread && (
                <button 
                  onClick={markAllRead}
                  className="text-[10px] font-black text-[#B1D34A] hover:underline"
                >
                  全部標為已讀
                </button>
              )}
            </div>
          </div>

          {/* List Area */}
          <div className="flex-1 overflow-y-auto hide-scrollbar space-y-3 pr-1">
            {notifications.length > 0 ? (
              notifications.map((item) => (
                <div 
                  key={item.id}
                  onClick={() => markAsRead(item.id)}
                  className={`p-4 rounded-2xl border-2 transition-all cursor-pointer relative group ${
                    item.isRead 
                      ? 'bg-[#FDFDFB] border-[#E9E9DB] opacity-75' 
                      : 'bg-[#F9F9F2] border-[#B1D34A]/30 shadow-sm'
                  }`}
                >
                  {/* Unread Indicator Dot */}
                  {!item.isRead && (
                    <div className="absolute top-3 right-3">
                      <div className="w-2.5 h-2.5 bg-[#B1D34A] rounded-full animate-pulse shadow-[0_0_8px_rgba(177,211,74,0.6)]" />
                    </div>
                  )}

                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-full flex items-center justify-center shrink-0 transition-colors ${
                      item.isRead 
                        ? 'bg-gray-100 text-gray-400' 
                        : (item.type === 'arrival' ? 'bg-[#F0F9EB] text-[#B1D34A]' : 'bg-[#FFF5F5] text-red-300')
                    }`}>
                      {item.type === 'arrival' ? <Plane size={24} className="rotate-45" /> : <Plane size={24} className="-rotate-135" />}
                    </div>

                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5">
                        <span className={`font-black text-sm truncate ${item.isRead ? 'text-[#8E8E81]' : 'text-[#5C5C4D]'}`}>
                          {item.user}
                        </span>
                        <span className="text-[10px] font-bold text-gray-400 shrink-0">{item.time}</span>
                      </div>
                      <p className={`text-[11px] font-bold truncate ${item.isRead ? 'text-gray-400' : 'text-[#8E8E81]'}`}>
                        {item.type === 'arrival' ? '已抵達您的島嶼' : '已離開您的島嶼'}
                      </p>
                      <p className={`text-[9px] font-black uppercase mt-0.5 ${item.isRead ? 'text-gray-300' : 'text-[#B1D34A]'}`}>
                        來自：{item.island}
                      </p>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center py-12 text-center space-y-3">
                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center text-gray-200">
                  <CheckCircle2 size={32} />
                </div>
                <p className="text-sm font-bold text-gray-300">目前沒有新消息</p>
              </div>
            )}
          </div>

          {/* Footer Actions */}
          <div className="pt-4 mt-auto border-t border-gray-100 flex gap-3">
            <button 
              onClick={() => {
                setNotifications([]);
                onClear();
              }}
              className="flex-1 py-3 bg-gray-50 text-gray-400 rounded-2xl font-bold text-xs flex items-center justify-center gap-2 hover:bg-gray-100 transition-colors"
            >
              <Trash2 size={14} /> 全部清空
            </button>
            <button 
              onClick={onClose}
              className="flex-1 py-3 bg-[#B1D34A] text-white rounded-2xl font-bold text-xs flex items-center justify-center gap-2 shadow-sm hover:brightness-105 transition-all"
            >
              <CheckCircle2 size={14} /> 我知道了
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

